ast.source:
.backup-details {
    font-size: 12px;
    color: var(--text-muted);
    white-space: normal !important;
    overflow: visible !important;
    text-overflow: clip !important;
    line-height: 1.5;
    margin-top: 4px;
}
.backup-detail-item {
    display: inline-block;
    margin-right: 8px;
    background: var(--background-secondary);
    padding: 2px 6px;
    border-radius: 4px;
    margin-bottom: 4px;
}
.create-backup-button {
    display: flex;
    padding: 10px;
    margin-bottom: 10px;
    background: var(--background-secondary);
    border-radius: 5px;
    align-items: center;
    cursor: pointer;
    transition: background-color 0.2s;
}
.create-backup-button:hover {
    background: var(--background-modifier-hover);
}
.create-backup-icon {
    margin-right: 8px;
    color: var(--text-accent);
}
.create-backup-text {
    flex-grow: 1;
}
.create-backup-text-main {
    font-weight: 500;
    margin-bottom: 2px;
}
.create-backup-text-sub {
    font-size: 12px;
    color: var(--text-muted);
}
.manual-backup-container {
    margin-bottom: 10px;
    padding: 10px;
    background: var(--background-secondary);
    border-radius: 5px;
}

